async fn authenticate(&mut self, cx: &Cx, method: AuthMethod) -> Outcome<(), Error> {
    match method {
        AuthMethod::ScramSha256 => {
            let mut scram = ScramClient::new(&self.config.user, &self.config.password);

            // Send SASL initial response
            self.send(FrontendMessage::SASLInitialResponse {
                mechanism: "SCRAM-SHA-256".to_string(),
                data: scram.client_first(),
            }).await?;

            // Receive SASL continue
            let msg = self.receive().await?;
            let data = match msg {
                BackendMessage::AuthenticationSASLContinue(data) => data,
                _ => return Err(Error::Protocol("Expected SASL continue")),
            };

            // Send SASL response
            let response = scram.process_server_first(&data)?;
            self.send(FrontendMessage::SASLResponse(response)).await?;

            // Receive SASL final
            let msg = self.receive().await?;
            let data = match msg {
                BackendMessage::AuthenticationSASLFinal(data) => data,
                _ => return Err(Error::Protocol("Expected SASL final")),
            };

            // Verify server
            scram.verify_server_final(&data)?;

            // Should receive AuthenticationOk next
            let msg = self.receive().await?;
            match msg {
                BackendMessage::AuthenticationOk => Ok(()),
                _ => Err(Error::Protocol("Expected AuthenticationOk")),
            }
        }
        // ... other methods
    }
}
