pub struct ScramClient {
    username: String,
    password: String,
    client_nonce: String,

    // State from server
    server_nonce: Option<String>,
    salt: Option<Vec<u8>>,
    iterations: Option<u32>,

    // Derived keys
    salted_password: Option<[u8; 32]>,
    auth_message: Option<String>,
}

impl ScramClient {
    pub fn new(username: &str, password: &str) -> Self {
        let client_nonce = generate_nonce();
        Self {
            username: username.to_string(),
            password: password.to_string(),
            client_nonce,
            server_nonce: None,
            salt: None,
            iterations: None,
            salted_password: None,
            auth_message: None,
        }
    }

    /// Generate client-first message
    pub fn client_first(&self) -> Vec<u8> {
        // gs2-header: "n,," (no channel binding, no authzid)
        // client-first-message-bare: "n=<user>,r=<nonce>"
        format!("n,,n={},r={}", self.username, self.client_nonce).into_bytes()
    }

    /// Process server-first message and generate client-final
    pub fn process_server_first(&mut self, data: &[u8]) -> Result<Vec<u8>, Error> {
        let msg = std::str::from_utf8(data)?;

        // Parse server-first: r=<nonce>,s=<salt>,i=<iterations>
        let mut combined_nonce = None;
        let mut salt = None;
        let mut iterations = None;

        for part in msg.split(',') {
            if let Some(value) = part.strip_prefix("r=") {
                combined_nonce = Some(value.to_string());
            } else if let Some(value) = part.strip_prefix("s=") {
                salt = Some(base64::decode(value)?);
            } else if let Some(value) = part.strip_prefix("i=") {
                iterations = Some(value.parse()?);
            }
        }

        let combined_nonce = combined_nonce.ok_or(Error::Protocol("Missing nonce"))?;
        let salt = salt.ok_or(Error::Protocol("Missing salt"))?;
        let iterations = iterations.ok_or(Error::Protocol("Missing iterations"))?;

        // Verify nonce starts with our client nonce
        if !combined_nonce.starts_with(&self.client_nonce) {
            return Err(Error::Protocol("Invalid server nonce"));
        }

        // Derive salted password using PBKDF2
        let salted_password = pbkdf2_hmac_sha256(
            self.password.as_bytes(),
            &salt,
            iterations,
        );

        // Build auth message
        let client_first_bare = format!("n={},r={}", self.username, self.client_nonce);
        let client_final_without_proof = format!("c=biws,r={}", combined_nonce);  // biws = base64("n,,")
        let auth_message = format!("{},{},{}", client_first_bare, msg, client_final_without_proof);

        // Calculate client proof
        let client_key = hmac_sha256(&salted_password, b"Client Key");
        let stored_key = sha256(&client_key);
        let client_signature = hmac_sha256(&stored_key, auth_message.as_bytes());
        let client_proof: Vec<u8> = client_key.iter()
            .zip(client_signature.iter())
            .map(|(a, b)| a ^ b)
            .collect();

        // Store for verification
        self.server_nonce = Some(combined_nonce.clone());
        self.salted_password = Some(salted_password);
        self.auth_message = Some(auth_message);

        // Build client-final message
        let client_final = format!(
            "c=biws,r={},p={}",
            combined_nonce,
            base64::encode(&client_proof)
        );

        Ok(client_final.into_bytes())
    }

    /// Verify server-final message
    pub fn verify_server_final(&self, data: &[u8]) -> Result<(), Error> {
        let msg = std::str::from_utf8(data)?;

        let server_signature = msg.strip_prefix("v=")
            .ok_or(Error::Protocol("Invalid server-final"))?;
        let server_signature = base64::decode(server_signature)?;

        // Calculate expected server signature
        let salted_password = self.salted_password.as_ref()
            .ok_or(Error::Protocol("Missing salted password"))?;
        let auth_message = self.auth_message.as_ref()
            .ok_or(Error::Protocol("Missing auth message"))?;

        let server_key = hmac_sha256(salted_password, b"Server Key");
        let expected_signature = hmac_sha256(&server_key, auth_message.as_bytes());

        if server_signature != expected_signature {
            return Err(Error::Authentication("Server signature mismatch"));
        }

        Ok(())
    }
}

