### Connection Establishment
```rust
impl PgConnection {
    pub async fn connect(cx: &Cx, config: PgConfig) -> Outcome<Self, Error> {
        // 1. TCP connect with timeout
        let stream = cx.with_budget(config.connect_timeout, async {
            TcpStream::connect(&format!("{}:{}", config.host, config.port)).await
        }).await?;

        let mut conn = Self {
            stream,
            state: ConnectionState::Connecting,
            process_id: 0,
            secret_key: 0,
            parameters: HashMap::new(),
            config,
            read_buf: Vec::with_capacity(8192),
            write_buf: Vec::with_capacity(8192),
            writer: MessageWriter::new(),
            statements: LruCache::new(100),
        };

        // 2. SSL negotiation (if configured)
        if conn.config.ssl_mode != SslMode::Disable {
            conn.negotiate_ssl(cx).await?;
        }

        // 3. Send startup message
        conn.send_startup(cx).await?;

        // 4. Handle authentication
        conn.state = ConnectionState::Authenticating;
        conn.handle_auth(cx).await?;

        // 5. Read remaining startup messages
        conn.read_startup_messages(cx).await?;

        conn.state = ConnectionState::Ready(TransactionStatus::Idle);
        Outcome::Ok(conn)
    }

    async fn send_startup(&mut self, cx: &Cx) -> Outcome<(), Error> {
        let mut params = vec![
            ("user".to_string(), self.config.user.clone()),
            ("database".to_string(), self.config.database.clone()),
            ("client_encoding".to_string(), "UTF8".to_string()),
        ];

        if let Some(app) = &self.config.application_name {
            params.push(("application_name".to_string(), app.clone()));
        }

        for (k, v) in &self.config.options {
            params.push((k.clone(), v.clone()));
        }

        let msg = FrontendMessage::Startup {
            version: 196608,  // 3.0
            params,
        };

        self.send_message(cx, &msg).await
    }

    async fn handle_auth(&mut self, cx: &Cx) -> Outcome<(), Error> {
        loop {
            let msg = self.receive_message(cx).await?;

            match msg {
                BackendMessage::AuthenticationOk => {
                    return Outcome::Ok(());
                }
                BackendMessage::AuthenticationCleartextPassword => {
                    let password = self.config.password.as_ref()
                        .ok_or(Error::Authentication("Password required"))?;
                    self.send_message(cx, &FrontendMessage::PasswordMessage(password.clone())).await?;
                }
                BackendMessage::AuthenticationMD5Password(salt) => {
                    let password = self.config.password.as_ref()
                        .ok_or(Error::Authentication("Password required"))?;
                    let hash = md5_password(&self.config.user, password, &salt);
                    self.send_message(cx, &FrontendMessage::PasswordMessage(hash)).await?;
                }
                BackendMessage::AuthenticationSASL(mechanisms) => {
                    if mechanisms.contains(&"SCRAM-SHA-256".to_string()) {
                        self.scram_auth(cx).await?;
                    } else {
                        return Outcome::Err(Error::Authentication("Unsupported SASL mechanism"));
                    }
                }
                BackendMessage::ErrorResponse(e) => {
                    return Outcome::Err(Error::from_pg_error(e));
                }
                _ => {
                    return Outcome::Err(Error::Protocol(format!("Unexpected message during auth: {:?}", msg)));
                }
            }
        }
    }

    async fn read_startup_messages(&mut self, cx: &Cx) -> Outcome<(), Error> {
        loop {
            let msg = self.receive_message(cx).await?;

            match msg {
                BackendMessage::BackendKeyData { process_id, secret_key } => {
                    self.process_id = process_id;
                    self.secret_key = secret_key;
                }
                BackendMessage::ParameterStatus { name, value } => {
                    self.parameters.insert(name, value);
                }
                BackendMessage::ReadyForQuery(status) => {
                    self.state = ConnectionState::Ready(status.into());
                    return Outcome::Ok(());
                }
                BackendMessage::ErrorResponse(e) => {
                    return Outcome::Err(Error::from_pg_error(e));
                }
                BackendMessage::NoticeResponse(_) => {
                    // Log but continue
                }
                _ => {
                    return Outcome::Err(Error::Protocol(format!("Unexpected startup message: {:?}", msg)));
                }
            }
        }
    }
}
