### Low-Level I/O
```rust
impl PgConnection {
    async fn send_message(&mut self, cx: &Cx, msg: &FrontendMessage) -> Outcome<(), Error> {
        cx.checkpoint()?;

        let data = self.writer.write(msg);
        self.stream.write_all(data).await?;
        self.stream.flush().await?;

        Outcome::Ok(())
    }

    async fn receive_message(&mut self, cx: &Cx) -> Outcome<BackendMessage, Error> {
        cx.checkpoint()?;

        // Read header (5 bytes: type + length)
        while self.read_buf.len() < 5 {
            let n = self.stream.read_buf(&mut self.read_buf).await?;
            if n == 0 {
                return Outcome::Err(Error::Connection(ConnectionError::disconnected()));
            }
        }

        let length = i32::from_be_bytes([
            self.read_buf[1],
            self.read_buf[2], 
            self.read_buf[3],
            self.read_buf[4],
        ]) as usize;

        // Read full message
        while self.read_buf.len() < length + 1 {
            let n = self.stream.read_buf(&mut self.read_buf).await?;
            if n == 0 {
                return Outcome::Err(Error::Connection(ConnectionError::disconnected()));
            }
        }

        // Parse message
        let msg_data = &self.read_buf[..length + 1];
        let msg = MessageReader::parse(msg_data)?;

        // Remove from buffer
        self.read_buf.drain(..length + 1);

        Outcome::Ok(msg)
    }
}
